  1	import { Alert, TableColumn, useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
  2	import { ExpandableRowContent, Table, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
  3	import React, { useMemo } from 'react';
  4	import { useTranslation } from 'react-i18next';
  5	import { getRuleUrl, usePerspective } from '../../../components/hooks/usePerspective';
  6	import { AggregatedAlert } from '../AlertsAggregates';
  7	import { AlertState, MonitoringResourceIcon, Severity } from '../AlertUtils';
  8	import AlertTableRow from './AlertTableRow';
  9	import { tableAggregatedAlertClasses } from './hooks/useAggregateAlertColumns';
 10	import { RuleResource } from '../../../components/utils';
 11	import { Link } from 'react-router-dom';
 12	import { SelectedFilters } from '../useSelectedFilters';
 13	import { filterAlerts } from './hooks/utils';
 14	import { Badge, Flex, FlexItem } from '@patternfly/react-core';
 15	
 16	type AggregateAlertTableRowProps = React.FC<{
 17	  aggregatedAlert: AggregatedAlert;
 18	  rowData: { rowIndex: number; selectedFilters: SelectedFilters };
 19	}>;
 20	
 21	const AggregateAlertTableRow: AggregateAlertTableRowProps = ({
 22	  aggregatedAlert,
 23	  rowData: { rowIndex, selectedFilters },
 24	}) => {
 25	  const [isExpanded, setIsExpanded] = React.useState(false);
 26	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 27	  const { perspective } = usePerspective();
 28	  const title = aggregatedAlert.name;
 29	  const isACMPerspective = perspective === 'acm';
 30	  const [namespace] = useActiveNamespace();
 31	
 32	  const filteredAlerts = useMemo(
 33	    () => filterAlerts(aggregatedAlert.alerts, selectedFilters),
 34	    [aggregatedAlert.alerts, selectedFilters],
 35	  );
 36	
 37	  const columns: TableColumn<Alert>[] = [
 38	    {
 39	      title: t('Name'),
 40	      id: 'alert-name',
 41	    },
 42	    {
 43	      title: t('Severity'),
 44	      id: 'alert-severity',
 45	    },
 46	    {
 47	      title: t('Namespace'),
 48	      id: 'alert-namespace',
 49	      props: { className: 'pf-m-width-30' },
 50	    },
 51	    {
 52	      title: t('State'),
 53	      id: 'alert-state',
 54	    },
 55	    {
 56	      title: t('Source'),
 57	      id: 'alert-source',
 58	    },
 59	    ...(isACMPerspective
 60	      ? [
 61	          {
 62	            title: t('Cluster'),
 63	            id: 'alert-cluster',
 64	          },
 65	        ]
 66	      : []),
 67	    {
 68	      title: '',
 69	      id: 'actions',
 70	    },
 71	  ];
 72	
 73	  const firstAlert = aggregatedAlert?.alerts?.[0];
 74	
 75	  return (
 76	    <Tbody key={title} isExpanded={isExpanded} role="rowgroup" className="aggregatedalert-row">
 77	      <Tr>
 78	        <Td
 79	          expand={{
 80	            rowIndex,
 81	            isExpanded,
 82	            onToggle: (event, rowIndex, isOpen) => setIsExpanded(isOpen),
 83	            expandId: 'expand-interfaces-list',
 84	          }}
 85	        />
 86	        <Td className={tableAggregatedAlertClasses[0]} title={title}>
 87	          <Flex spaceItems={{ default: 'spaceItemsNone' }} flexWrap={{ default: 'nowrap' }}>
 88	            <FlexItem>
 89	              <MonitoringResourceIcon resource={RuleResource} />
 90	            </FlexItem>
 91	            <FlexItem>
 92	              <Link
 93	                to={getRuleUrl(
 94	                  perspective,
 95	                  firstAlert?.rule,
 96	                  firstAlert?.labels?.namespace || namespace,
 97	                )}
 98	                data-test-id="alert-resource-link"
 99	              >
100	                {aggregatedAlert.name}
101	              </Link>
102	            </FlexItem>
103	          </Flex>
104	        </Td>
105	        <Td className={tableAggregatedAlertClasses[1]} title={title}>
106	          <Severity severity={aggregatedAlert.severity} />
107	        </Td>
108	        <Td className={tableAggregatedAlertClasses[2]} title={title}>
109	          <Badge key={1} isRead>
110	            {filteredAlerts.length}
111	          </Badge>
112	        </Td>
113	        <Td className={tableAggregatedAlertClasses[3]} title={title}>
114	          {Array.from(aggregatedAlert.states).map((state) => (
115	            <AlertState state={state} key={state} />
116	          ))}
117	        </Td>
118	      </Tr>
119	      <Tr isExpanded={isExpanded} className={`aggregatedalert-row__expanded-${isExpanded}`}>
120	        <Td colSpan={isACMPerspective ? 6 : 5}>
121	          <ExpandableRowContent>
122	            <Table>
123	              <Thead className="aggregatedalert-row__alert-table-head">
124	                <Tr>
125	                  {columns.map((column) => (
126	                    <Th key={column.id} {...column?.props}>
127	                      {column.title}
128	                    </Th>
129	                  ))}
130	                </Tr>
131	              </Thead>
132	              {filteredAlerts.map((alert) => (
133	                <AlertTableRow alert={alert} key={alert.activeAt} />
134	              ))}
135	            </Table>
136	          </ExpandableRowContent>
137	        </Td>
138	      </Tr>
139	    </Tbody>
140	  );
141	};
142	
143	export default AggregateAlertTableRow;

